// quoteClickJS builds the data-on:click expression for a forum post quote
// button. AuthorName goes through strconv.Quote so names with quotes or
// backslashes remain safe inside the JS expression.
func quoteClickJS(postID, authorName string) string {
	return "$quoted_post_id=" + strconv.Quote(postID) + "; $_reply_quote_label=" + strconv.Quote(authorName)
}

// jsString returns a JS-safe string body — without quotes — for inline
// data-on:click expressions. Caller wraps it in ” (or "").
func jsString(s string) string {
	q := strconv.Quote(s)
	return q[1 : len(q)-1]
}

