func filterClass(self, cur string) string {
	if self == cur {
		return "filter active"
	}
	return "filter"
}

func forumFilterHref(slug, status, q string) string {
	out := "/c/" + slug + "/forum?status=" + status
	if q != "" {
		out += "&q=" + queryEscape(q)
	}
	return out
}

func queryEscape(s string) string {
	// minimal escape — '&' and '#' are the only chars that would break the URL
	// parsing on the receiving end; everything else is fine inside the value.
	r := []rune(s)
	out := make([]rune, 0, len(r))
	for _, c := range r {
		switch c {
		case '&':
			out = append(out, '%', '2', '6')
		case '#':
			out = append(out, '%', '2', '3')
		case ' ':
			out = append(out, '+')
		default:
			out = append(out, c)
		}
	}
	return string(out)
}

